    async importStandards(jsonContent: string, programId: string): Promise<Standard[]> {
        const parsed = JSON.parse(jsonContent);
        const newStandards: Standard[] = Object.entries(parsed).map(([id, data]: [string, any]) => ({
            programId,
            standardId: id,
            description: data.Description,
            section: data.Chapter,
            subStandards: data.EPs.map((ep: any, index: number) => ({
                id: `${id}.${index + 1}`,
                description: ep,
            }))
        }));
        const allStandards = [...this.getStandards(), ...newStandards];
        await dataService.setStandards(allStandards);
        return newStandards;
    }

