    async assignTraining(data: { trainingId: string; userIds: string[]; departmentIds: string[]; dueDate?: string }): Promise<void> {
        const usersToUpdate = new Set<string>(data.userIds);
        if (data.departmentIds.length > 0) {
            this.getUsers().forEach(u => {
                if (u.departmentId && data.departmentIds.includes(u.departmentId)) {
                    usersToUpdate.add(u.id);
                }
            });
        }

        const newAssignment = {
            trainingId: data.trainingId,
            assignedDate: new Date().toISOString(),
            dueDate: data.dueDate,
        };

        const users = this.getUsers().map(u => {
            if (usersToUpdate.has(u.id) && !u.trainingAssignments.some(a => a.trainingId === data.trainingId)) {
                return { ...u, trainingAssignments: [...u.trainingAssignments, newAssignment] };
            }
            return u;
        });

        await dataService.setUsers(users);
    }

    async submitQuiz(userId: string, trainingId: string, answers: { [questionId: string]: number }): Promise<{ result: any, newCertificate: CertificateData | null }> {
        const program = this.getTrainingPrograms().find(p => p.id === trainingId)!;
        let correct = 0;
        program.quiz.forEach(q => {
            if (answers[q.id] === q.correctOptionIndex) {
                correct++;
            }
        });
        const score = Math.round((correct / program.quiz.length) * 100);
        const passed = score >= program.passingScore;
        const user = this.getUsers().find(u => u.id === userId)!;

        const result = {
            status: 'Completed' as const,
            score,
            completionDate: new Date().toISOString(),
            certificateId: passed ? `cert-${userId}-${trainingId}` : undefined,
        };

        let newCertificate: CertificateData | null = null;
        if (passed) {
            newCertificate = {
                id: result.certificateId!,
                userId,
                userName: user.name,
                trainingId,
                trainingTitle: program.title,
                completionDate: result.completionDate,
                score,
            };
            const certs = [...this.getCertificates(), newCertificate];
            await dataService.setCertificates(certs);
        }

        const statuses = this.getUserTrainingStatuses();
        statuses[userId] = { ...statuses[userId], [trainingId]: result };
        await dataService.setUserTrainingStatuses(statuses);

        return { result, newCertificate };
    }

