    async runAudit(planId: string): Promise<Audit> {
        const plan = this.getAuditPlans().find(p => p.id === planId)!;
        const project = this.getProjects().find(p => p.id === plan.projectId)!;
        const itemsToAudit = project.checklist.slice(0, plan.itemCount); // Simplified logic
        const newAudit: Audit = {
            id: `audit-${Date.now()}`,
            planId,
            dateConducted: new Date().toISOString(),
            auditorId: plan.assignedAuditorId,
            results: itemsToAudit.map(item => ({
                checklistItemId: item.id,
                isCompliant: Math.random() > 0.3, // 70% chance of compliance
                auditorNotes: 'Auditor observation notes.'
            }))
        };
        const audits = [...this.getAudits(), newAudit];
        await dataService.setAudits(audits);
        return newAudit;
    }
